namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText);
}

namespace DocSummary.Services;

public class DocumentSummaryService : IDocumentSummaryService
{
    private const int MaxSentencesInSummary = 3;

    public string Summarize(string documentText)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        var sentences = documentText
            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(s => s.Length > 0)
            .ToList();

        if (sentences.Count == 0)
            return string.Empty;

        var summaryParts = sentences.Take(MaxSentencesInSummary);
        return string.Join(". ", summaryParts) + ".";
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText must not be empty.");

        var summary = _summaryService.Summarize(request.DocumentText);

        return Ok(new SummarizeResponse { Summary = summary });
    }
}

